14	const FIRST_INSURANCE_MULTIPLIER = 1.1;
15	const POST_FIRST_CONTRACT_MULTIPLIER = 0.85;
16	const CURSED_MULTIPLIER = 1.5;
17	const HIGH_ENCHANTMENT_MULTIPLIER = 1.3;
18	const LOYALTY_MULTIPLIER = 0.8;
19	const LOYALTY_YEARS_THRESHOLD = 2;
20	const ADMIN_FEE = 5;
21	
22	// Three alike pieces of a "building-block" item (rune, moonstone, …) pool
23	// to a single unit priced at this fixed tier, irrespective of the per-piece
24	// BASE_PRICE. The tier coincidentally equals amulet's base price today but
25	// is conceptually a separate pricing rule from the per-item ladder.
26	const BUILDING_BLOCK_PRICE = 60;
27	
28	const BASE_PRICE: Record<string, number> = {
29	  sword: 100,
30	  staff: 80,
31	  amulet: 60,
32	  potion: 40,
33	  rune: 25,
34	  moonstone: 25,
35	};
36	
37	const POOLED_TYPES = new Set(["rune", "moonstone"]);
38	
39	function itemModifierMultiplier(item: Item): number {
40	  const cursed = item.cursed ? CURSED_MULTIPLIER : 1;
41	  const highEnchantment =
42	    (item.enchantment ?? 0) >= 5 ? HIGH_ENCHANTMENT_MULTIPLIER : 1;
43	  return cursed * highEnchantment;
44	}
45	
46	// MHPCO always rounds the euro value of a discounted/loaded price upward
47	// (in the office's favour). The toFixed(10) step strips IEEE-754 drift so
48	// values that are mathematically integer (e.g. 100 × 1.10 = 110) don't get
49	// bumped up a euro by a 110.00000000000001 representation.
50	function ceilInMhpcoFavor(value: number): number {
51	  return Math.ceil(Number(value.toFixed(10)));
52	}
53	
54	// Sum of per-item base prices (with item-attribute multipliers applied)
55	// for a single quote. Building-block items (rune today, moonstone in cycle
56	// 13) are pooled in groups of three at BUILDING_BLOCK_PRICE; leftovers fall
57	// back to the per-piece BASE_PRICE.
58	function quoteItemsSubtotal(items: Item[]): number {
59	  let subtotal = 0;
60	  const pooledCounts = new Map<string, number>();
61	  for (const item of items) {
62	    if (POOLED_TYPES.has(item.type)) {
63	      pooledCounts.set(item.type, (pooledCounts.get(item.type) ?? 0) + 1);
64	    } else {
65	      subtotal += BASE_PRICE[item.type] * itemModifierMultiplier(item);
66	    }
67	  }
68	  for (const [type, count] of pooledCounts) {
69	    const buildingBlocks = Math.floor(count / 3);
70	    const loose = count % 3;
71	    subtotal += buildingBlocks * BUILDING_BLOCK_PRICE + loose * BASE_PRICE[type];
72	  }
73	  return subtotal;
74	}
75	
76	export function runScenario(scenario: unknown): unknown {
77	  const { customer, steps } = scenario as Scenario;
78	  const loyaltyMultiplier =
79	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? LOYALTY_MULTIPLIER : 1;
80	  const results = steps.map((step, quoteIndex) => {
81	    if (step.op === "claim") {
82	      return { payout: 0 };
83	    }
84	    const itemsSubtotal = quoteItemsSubtotal(step.items);
85	    const contractMultiplier =
86	      quoteIndex === 0 ? FIRST_INSURANCE_MULTIPLIER : POST_FIRST_CONTRACT_MULTIPLIER;
87	    const premium =
88	      ceilInMhpcoFavor(itemsSubtotal * loyaltyMultiplier * contractMultiplier) +
89	      ADMIN_FEE;
90	    return { premium };
91	  });
92	  return { results };
93	}
